#include "basic_stack.h"\n\nvoid BasicStack::push(int val) {\n    std::lock_guard<std::mutex> lock(mutex_);\n    data.push(val);\n}\n\nint BasicStack::pop() {\n    std::lock_guard<std::mutex> lock(mutex_);\n    if (data.empty()) {\n        throw std::out_of_range("Stack is empty");\n    }\n    int val = data.top();\n    data.pop();\n    return val;\n}\n\nint BasicStack::top() const {\n    std::lock_guard<std::mutex> lock(mutex_);\n    if (data.empty()) {\n        throw std::out_of_range("Stack is empty");\n    }\n    return data.top();\n}\n\nbool BasicStack::empty() const {\n    std::lock_guard<std::mutex> lock(mutex_);\n    return data.empty();\n}\n